sql:
SELECT u.username, COUNT(DISTINCT u.role) AS number_of_hats
FROM users u
GROUP BY u.user_id, u.username;

external_knowledge:
- 'macroeconomic' and 'financial' indicators refer to economic indicators that describe the overall performance and trends of an economy, and financial indicators that describe the financial health and performance of various sectors; 
- 'Q' and 'M' frequencies refer to quarterly and monthly data collection frequencies, respectively;
- a 'region' refers to a geographical or administrative division, in this case the 'USA';
- 'john_doe' refers to a specific user who has provided the data points.

sql:
SELECT AVG(value) AS average_value
FROM data_points
WHERE region_id = 1 AND indicator_id = 102;

SELECT DISTINCT r.name
FROM regions r
JOIN data_points d ON r.region_id = d.region_id;
